jQuery(function(){jQuery(document).on("agm_google_maps-admin-options_initialized",function(e,l,a){var o='<label for="agm-kml_uploaded_file">Select a KML file</label>';jQuery.post(window.ajaxurl,{action:"agm_list_kml_uploads",nonce:_agm.nonce},function(e){o+='<select class="widefat" id="agm-kml_uploaded_file">',o+='<option value="">Select a KML file</option>',jQuery.each(e,function(e,l){o+='<option value="'+l+'">'+e+"</option>"}),o+="</select>",jQuery("#agm-kml_uploader").length||jQuery("#agm-kml_url_overlay").append('<div id="agm-kml_uploader"></div>'),jQuery("#agm-kml_uploader").html(o),jQuery("#agm-kml_uploaded_file").change(function(){jQuery("#agm-kml_url").val(jQuery(this).val())})})})});